// Receives output from 'Query High Scores' HTTP Request node.
// Supabase RPC exec_query returns a JSON array. When continueOnFail
// is active, errors arrive as items with an 'error' property.
//
// This node builds the full Telegram message and routes output:
//   - Output 0: message ready to send (always exactly 1 item)

const items = $input.all();
const today = new Date().toISOString().slice(0, 10);

// --- Detect HTTP error (continueOnFail puts error info in item) ---
const firstItem = items[0]?.json;
if (firstItem?.error || (firstItem?.statusCode && firstItem.statusCode >= 400)) {
  const errorMsg = firstItem.error?.message || firstItem.message || firstItem.error || 'Error desconocido';
  return [{
    json: {
      text: `<b>\ud83d\udd0d Se\u00f1ales del D\u00eda \u2014 Trading Memes</b>\n` +
            `<b>Fecha:</b> ${today}\n\n` +
            `\u274c <b>ERROR</b>: Fallo al consultar Supabase.\n` +
            `<code>${errorMsg}</code>\n\n` +
            `Verificar conectividad con Supabase y la tabla scores.`,
      chat_id: '1558705287'
    }
  }];
}

// --- Parse candidates ---
// Supabase RPC may return the array as a single item (json is the array)
// or n8n may split each row into a separate item.
let candidates = [];
if (Array.isArray(firstItem)) {
  // Single item containing the full array
  candidates = firstItem;
} else if (firstItem && firstItem.token_id) {
  // n8n split each row into its own item
  candidates = items.map(i => i.json);
} else if (firstItem && Array.isArray(firstItem.result)) {
  // Wrapped in a result key
  candidates = firstItem.result;
}

// --- No candidates at all ---
if (!candidates || candidates.length === 0) {
  return [{
    json: {
      text: `<b>\ud83d\udd0d Se\u00f1ales del D\u00eda \u2014 Trading Memes</b>\n` +
            `<b>Fecha:</b> ${today}\n\n` +
            `\u2139\ufe0f No se detectaron tokens con probabilidad \u2265 0.65 hoy.`,
      chat_id: '1558705287'
    }
  }];
}

// --- Check if scores are actually from today ---
const hasScoresToday = candidates.some(c => {
  if (!c.scored_at) return false;
  return c.scored_at.slice(0, 10) === today;
});

if (!hasScoresToday) {
  return [{
    json: {
      text: `<b>\ud83d\udd0d Se\u00f1ales del D\u00eda \u2014 Trading Memes</b>\n` +
            `<b>Fecha:</b> ${today}\n\n` +
            `\u26a0\ufe0f No hay scores para hoy. Verificar daily-collect.`,
      chat_id: '1558705287'
    }
  }];
}

// --- Group by chain ---
const chainConfig = {
  'solana':   { emoji: '\ud83d\udfe2', label: 'Solana',   dex: 'solana' },
  'ethereum': { emoji: '\ud83d\udd35', label: 'Ethereum', dex: 'ethereum' },
  'base':     { emoji: '\ud83d\udfe1', label: 'Base',     dex: 'base' }
};

const grouped = {};
for (const c of candidates) {
  const chain = (c.chain || 'unknown').toLowerCase();
  if (!grouped[chain]) grouped[chain] = [];
  grouped[chain].push(c);
}

// --- Build message ---
let msg = `<b>\ud83d\udd0d Se\u00f1ales del D\u00eda \u2014 Trading Memes</b>\n`;
msg += `<b>Fecha:</b> ${today}\n`;
msg += `<b>Tokens detectados:</b> ${candidates.length}\n`;

const chainOrder = ['solana', 'ethereum', 'base'];

for (const chain of chainOrder) {
  const tokens = grouped[chain];
  if (!tokens || tokens.length === 0) continue;

  const config = chainConfig[chain] || { emoji: '\u26aa', label: chain, dex: chain };
  msg += `\n<b>${config.emoji} ${config.label} (${tokens.length})</b>\n`;

  tokens.forEach((t, i) => {
    const prob = (t.probability * 100).toFixed(1);
    const address = t.pool_address || t.address || '';
    const link = `https://dexscreener.com/${config.dex}/${address}`;
    const name = t.name || 'Unknown';
    const symbol = t.symbol || '???';
    const signal = t.signal || 'N/A';

    msg += `${i + 1}. <b>${name}</b> (${symbol}) \u2014 Score: ${prob}%\n`;
    msg += `   Signal: ${signal} | <a href="${link}">DexScreener</a>\n`;
  });
}

// Handle any chains not in chainOrder
for (const chain of Object.keys(grouped)) {
  if (chainOrder.includes(chain)) continue;
  const tokens = grouped[chain];
  msg += `\n<b>\u26aa ${chain} (${tokens.length})</b>\n`;
  tokens.forEach((t, i) => {
    const prob = (t.probability * 100).toFixed(1);
    const address = t.pool_address || t.address || '';
    const link = `https://dexscreener.com/${chain}/${address}`;
    msg += `${i + 1}. <b>${t.name || 'Unknown'}</b> (${t.symbol || '???'}) \u2014 Score: ${prob}%\n`;
    msg += `   Signal: ${t.signal || 'N/A'} | <a href="${link}">DexScreener</a>\n`;
  });
}

// Overflow note (query is already LIMIT 20 but defensive)
if (candidates.length > 20) {
  msg += `\n+${candidates.length - 20} m\u00e1s\n`;
}

msg += `\n\u26a0\ufe0f Esto NO es consejo financiero. DYOR.`;

return [{
  json: {
    text: msg,
    chat_id: '1558705287'
  }
}];
